module RefModule(
input	[2:0]codes,
output	zero,
output	double,
output	negation
);
wire	A;
assign	A=codes[2];
wire	B;
assign	B=codes[1];
wire	C;
assign	C=codes[0];
wire	unused_nB,nC,nA;
assign	unused_nB=~B;
assign	nC=~C;
assign	nA=~A;
wire	BC;
assign	BC=B&C;
wire	nBnC;
assign	nBnC=unused_nB&nC;
wire	nBanC;
assign	nBanC=unused_nB|nC;
assign	double=(nBnC&A)|(BC&nA);
assign	negation=A&nBanC;
assign	zero=(A&BC)|(nA&nBnC);
endmodule
